const raw = $input.first()?.json || {};
const body = raw.body || {};
const data = raw.chat_id ? raw : (body.chat_id ? body : raw);

const chat_id = Number(data.chat_id ?? 0);
const user_profile = data.user_profile || { registered: false, full_name: null, email: null };

return [{
  json: {
    chat_id: chat_id,
    sessionId: String(chat_id),
    text: String(data.text ?? '').trim(),
    user_profile: user_profile,
    intent: 'general_chat',
    _meta: {
      source: 'NN_03-B_Pipeline_Agent',
      timestamp: new Date().toISOString(),
      version: '2.5.0'
    }
  }
}];

const chatIdStr = String($json.chat_id ?? '');
const chat_id_valid = chatIdStr.length > 0 && [...chatIdStr].every(c => c >= '0' && c <= '9');
const text = String($('Input_Clean').first().json.text ?? '').trim();
const text_valid = text.length > 2 && text.length < 500;

return [{
  json: {
    ...$json,
    isValid: chat_id_valid && text_valid
  }
}];

// Route By Validation - Gate+Skip pattern (§5.1 GEMINI.md)
// Reemplaza IF node v2.3 'Is Valid Payload?' para evitar bug
const input = $input.first().json;
const isValid = input.isValid === true;

return [{ json: {
  ...input,
  _route: isValid ? 'execute' : 'validation_error'
}}];

// Gate Execute Valid - solo pasa items válidos
const input = $input.first().json;
if (input._route !== 'execute') return [];
return [{ json: input }];

// Gate Skip Invalid - solo pasa errores
const input = $input.first().json;
if (input._route === 'execute') return [];
return [{ json: input }];

return [{
  json: {
    success: false,
    error_code: 'VALIDATION_ERROR',
    error_message: 'Datos de entrada inválidos: chat_id debe ser numérico y text entre 3-499 chars',
    data: null,
    _meta: {
      source: 'NN_03-B_Pipeline_Agent',
      timestamp: new Date().toISOString(),
      version: '2.2.0'
    }
  }
}];

const textLower = String($('Input_Clean').first().json.text || '').toLowerCase();

const PROFANITY_WORDS = ['conchetumare','ctm','culiao','qliao','pichula','tula','zorra','maraco','maricón','maricon','puta','mierda','fuck','shit','asshole','bitch','bastard','motherfucker','dick','cunt','pussy','prick','estúpido','estupido','idiota','imbécil','imbecil','gilipollas','huevon','weon'];

const INJECTION_PHRASES = [
  'ignore all previous instructions', 'disregard all rules', 'system prompt',
  'jailbreak', 'dan mode', 'olvida todas las instrucciones'
];

const OFFTOPIC_PHRASES = [
  'escribe un poema', 'write a poem', 'cuéntame un cuento', 'cuentame un cuento',
  'tell me a story', 'genera código', 'genera codigo', 'create code',
  'hackear', 'hacking', 'política', 'politica'
];

let isBlocked = false;

let tClean = '';
for(let i=0;i<textLower.length;i++) {
   const c = textLower[i];
   if (c==='.'||c===','||c==='!'||c==='?'||c==='('||c===')') tClean += ' '; else tClean += c;
}
const words = tClean.split(' ');
for(const w of words) { if (PROFANITY_WORDS.includes(w)) { isBlocked = true; break; } }
if (!isBlocked) {
  for (const phrase of INJECTION_PHRASES) {
    if (textLower.includes(phrase)) { isBlocked = true; break; }
  }
}
if (!isBlocked) {
  for (const phrase of OFFTOPIC_PHRASES) {
    if (textLower.includes(phrase)) { isBlocked = true; break; }
  }
}

return [{ json: { ...$json, isBlocked } }];

// Route - Gate+Skip pattern
const input = $input.first().json;
const isTrue = input.success === true || input.isBlocked === false;
return [{ json: { ...input, _route: isTrue ? 'execute' : 'skip' } }];

return [{
  json: {
    success: false,
    error_code: 'SECURITY_BLOCKED',
    error_message: 'Mensaje bloqueado por reglas de seguridad',
    data: null,
    _meta: {
      source: 'NN_03-B_Pipeline_Agent',
      timestamp: new Date().toISOString(),
      version: '2.2.0'
    }
  }
}];

