const jsonMatch = content.match(/\{[\s\S]*\}/);
let params = {};

if (!jsonMatch) {
  return [{ json: { success: false, data: null, _meta: { source: 'NN_03-B_Pipeline_Agent', timestamp: new Date().toISOString() }, error_code: 'PARSE_ERROR', error_message: 'No se detectó JSON en la respuesta del modelo.' };
}

try {
  params = JSON.parse(jsonMatch[0]);
} catch(e) {
  return [{ json: { success: false, data: null, _meta: { source: 'NN_03-B_Pipeline_Agent', timestamp: new Date().toISOString() }, error_code: 'JSON_INVALID', error_message: 'El JSON extraído es inválido.' };
}

params.chat_id = $('Input_Clean').first().json.chat_id || 0;

const bookingId = String(params.booking_id || '').trim();
const isUUID = bookingId.length === 36 && bookingId.split('-').length === 5;
const shortParts = bookingId.toUpperCase().split('BKG-'); const isShort = bookingId.toUpperCase().startsWith('BKG-') && shortParts[1] && shortParts[1].length >= 6 && shortParts[1].length <= 10;
if (!isUUID && !isShort) {
  // HARD FALLBACK: buscar código corto en el texto original si el LLM no lo puso en el JSON
  const userText = $('Input_Clean').first().json.text;
  let extractedShort = null;
  const tUpper = userText.toUpperCase();
  const bkgIdx = tUpper.indexOf('BKG-');
  if (bkgIdx !== -1) {
    let code = '';
    for(let i=bkgIdx+4; i<tUpper.length; i++) {
       const c = tUpper.charCodeAt(i);
       if ((c>=48 && c<=57) || (c>=65 && c<=90)) { code += tUpper[i]; } else break;
    }
    if (code.length >= 6 && code.length <= 10) extractedShort = 'BKG-' + code;
  }
  if (extractedShort) {
    params.booking_id = extractedShort;
  } else {
    return [{ json: {
      success: false,
      error_code: 'INVALID_BOOKING_ID',
      error_message: 'No se encontró un código de reserva válido (ej: BKG-123456).'
    };
  }
} else {
  params.booking_id = bookingId.toUpperCase();
}

return [{ json: params }];

