let params = {};

try {
  params = JSON.parse(jsonMatch ? jsonMatch[0] : '{}');
} catch(e) { params = {}; }

const cleanInput = $('Input_Clean').first().json;

return [{ json: { 
  chat_id: cleanInput.chat_id,
  provider_id: params.provider_id || 1,
  service_id: params.service_id || 1,
  preferred_date: params.preferred_date || new Date().toISOString().split('T')[0]
} }];

const items = $input.all().map(i => i.json);
const successItem = items.find(i => i.success === true);

if (successItem) return [{ json: successItem }];

const errorItem = items.find(i => i.error_code);
if (errorItem) return [{ json: errorItem }];

return [{ json: {
  success: false,
  error_code: 'PIPELINE_ERROR',
  error_message: 'No valid response generated from any branch',
  data: null,
  _meta: { source: 'NN_03-B_Pipeline_Agent', timestamp: new Date().toISOString() }
} }];

// Route - Gate+Skip pattern
const input = $input.first().json;
const isTrue = input.success === true || input.isBlocked === false;
return [{ json: { ...input, _route: isTrue ? 'execute' : 'skip' } }];

// ✅ CORRECTO --- leer error del json del item entrante
const input = $input.first()?.json || {};

// Los errores llegan como campos en el json, no en $input.params
const errorCode = input.error_code || input.code || "EXECUTION_ERROR";
const errorMessage = input.error_message || input.message || input.error || "Error desconocido";

return [{
  json: {
    success: false,
    error_code: errorCode,
    error_message: errorMessage,
    data: null,
    _meta: {
      source: "NN_03-B_Pipeline_Agent",
      timestamp: new Date().toISOString(),
      version: "2.2.0"
    }
  }
}];

const input = $input.first()?.json || {};
let aiResp = input.text || input.output || input.ai_response || '';
if (typeof aiResp === 'string') aiResp = aiResp.replace(/^[\"']|[\"']$/g, '').trim();
if (!aiResp) aiResp = 'Lo siento, no pude procesar tu solicitud.';

let chatId = 0;
try { 
  if ($('Input_Clean').isExecuted) {
    chatId = $('Input_Clean').first().json.chat_id || 0; 
  }
} catch(e) {}

let debugTopic = null;
try {
  if ($('Parse: get_services').isExecuted) {
    debugTopic = $('Parse: get_services').first()?.json?.query ?? null;
  }
} catch(e) { /* nodo no ejecutado en esta rama */ }

let intent = "general_chat";
try {
  if ($('Intent Normalizer').isExecuted) {
    intent = $('Intent Normalizer').first()?.json?.intent ?? "general_chat";
  }
} catch(e) {}

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      intent,
      chat_id: chatId,
      ai_response: aiResp
    },
    _meta: {
      source: 'NN_03-B_Pipeline_Agent',
      timestamp: new Date().toISOString(),
      debug_topic: debugTopic,
      version: '2.2.0'
    }
  }
}];

// Build Prompt: get_services
const sql = $('Analyze Resolve').first().json.sql_context || {};
const ragDocs = $json.data?.documents || [];
const userText = $('Input_Clean').first().json.text;

let prompt = `Eres la recepcionista amable de Booking Titanium. Responde la duda del usuario.\n\n`;

if (sql.resolved) {
  prompt += `### INFORMACIÓN OFICIAL DEL SERVICIO\n`;
  prompt += `- Nombre: ${sql.service_name}\n`;
  prompt += `- Precio: ${sql.price || 'Consultar'} ${sql.currency || 'USD'}\n\n`;
}

if (ragDocs.length > 0) {
  prompt += `### DOCUMENTACIÓN ADICIONAL\n`;
  prompt += JSON.stringify(ragDocs) + `\n\n`;
}

prompt += `### MENSAJE DEL USUARIO\n${userText}\n\n`;
prompt += `INSTRUCCIÓN: Responde de forma breve (máximo 3 oraciones), profesional y amable en ESPAÑOL.`;

return [{ json: { prompt } }];

const content = $json.text || '';
const jsonMatch = content.match(/\{[\s\S]*\}/);
let params = {};

try {
  params = JSON.parse(jsonMatch ? jsonMatch[0] : '{}');
} catch(e) { params = {}; }

const userText = $('Input_Clean').first().json.text;
const userTextLower = userText.toLowerCase();
let bookingId = params.booking_id || "";

// HARD FALLBACK for UUID or Short Code
if (!bookingId || bookingId.includes('AQUÍ') || bookingId === 'UUID') {
  let extractedShort = null;
  const tUpper = userText.toUpperCase();
  const bkgIdx = tUpper.indexOf('BKG-');
  if (bkgIdx !== -1) {
    let code = '';
    for(let i=bkgIdx+4; i<tUpper.length; i++) {
       const c = tUpper.charCodeAt(i);
       if ((c>=48 && c<=57) || (c>=65 && c<=90)) { code += tUpper[i]; } else break;
    }
    if (code.length >= 6 && code.length <= 10) extractedShort = 'BKG-' + code;
  }
  let extractedUuid = null;
  if (!extractedShort && userText.includes('-')) {
     const wArr = userText.split(' ');
     for(const w of wArr) {
        let cleanW = '';
        for(let i=0;i<w.length;i++) {
           const c = w.charCodeAt(i);
           if ((c>=48&&c<=57)||(c>=65&&c<=90)||(c>=97&&c<=122)||c===45) cleanW += w[i];
        }
        if (cleanW.length === 36 && cleanW.split('-').length === 5) { extractedUuid = cleanW; break; }
     }
  }

  if (extractedUuid) bookingId = extractedUuid;
  else if (extractedShort) bookingId = extractedShort;
